/**
 * Reverses the bits in a byte value for little endian processing.
 * @param b the byte value (as int)
 * @return the byte with bits reversed
 */
private static int reverseBits(int b) {
    b = ((b & 0x55) << 1) | ((b & 0xAA) >> 1);  // Swap adjacent bits
    b = ((b & 0x33) << 2) | ((b & 0xCC) >> 2);  // Swap adjacent pairs
    b = ((b & 0x0F) << 4) | ((b & 0xF0) >> 4);  // Swap nibbles
    return b;
}

